import { useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { RealtimeChannel } from '@supabase/supabase-js'

export function useSupabase<T extends Record<string, any>>(tableName: string) {
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const supabase = createClient()

    // CREATE
    const insert = useCallback(
        async (data: Partial<T>) => {
            try {
                setLoading(true)
                setError(null)
                const { data: result, error } = await supabase
                    .from(tableName)
                    .insert(data)
                    .select()
                    .single()
                if (error) throw error
                return result as T
            } catch (err: any) {
                setError(err.message)
                throw err
            } finally {
                setLoading(false)
            }
        },
        [tableName]
    )

    // READ ALL
    const getAll = useCallback(async () => {
        try {
            setLoading(true)
            setError(null)
            const { data, error } = await supabase
                .from(tableName)
                .select('*')
                .order('created_at', { ascending: false })
            if (error) throw error
            return data as T[]
        } catch (err: any) {
            setError(err.message)
            throw err
        } finally {
            setLoading(false)
        }
    }, [tableName])

    // READ ONE
    const getById = useCallback(
        async (id: string) => {
            try {
                setLoading(true)
                setError(null)
                const { data, error } = await supabase
                    .from(tableName)
                    .select('*')
                    .eq('id', id)
                    .single()
                if (error) throw error
                return data as T
            } catch (err: any) {
                setError(err.message)
                throw err
            } finally {
                setLoading(false)
            }
        },
        [tableName]
    )

    // UPDATE
    const update = useCallback(
        async (id: string, data: Partial<T>) => {
            try {
                setLoading(true)
                setError(null)
                const { data: result, error } = await supabase
                    .from(tableName)
                    .update(data)
                    .eq('id', id)
                    .select()
                    .single()
                if (error) throw error
                return result as T
            } catch (err: any) {
                setError(err.message)
                throw err
            } finally {
                setLoading(false)
            }
        },
        [tableName]
    )

    // DELETE
    const remove = useCallback(
        async (id: string) => {
            try {
                setLoading(true)
                setError(null)
                const { error } = await supabase
                    .from(tableName)
                    .delete()
                    .eq('id', id)
                if (error) throw error
            } catch (err: any) {
                setError(err.message)
                throw err
            } finally {
                setLoading(false)
            }
        },
        [tableName]
    )

    // QUERY with filters
    const query = useCallback(
        async (filters: { column: string; operator: string; value: any }[]) => {
            try {
                setLoading(true)
                setError(null)
                let queryBuilder = supabase.from(tableName).select('*')
                for (const filter of filters) {
                    queryBuilder = queryBuilder.filter(filter.column, filter.operator, filter.value)
                }
                const { data, error } = await queryBuilder
                if (error) throw error
                return data as T[]
            } catch (err: any) {
                setError(err.message)
                throw err
            } finally {
                setLoading(false)
            }
        },
        [tableName]
    )

    // REALTIME SUBSCRIPTION (replaces Firebase onSnapshot)
    const subscribe = useCallback(
        (callback: (data: T[]) => void): (() => void) => {
            // First, fetch initial data
            supabase
                .from(tableName)
                .select('*')
                .order('created_at', { ascending: false })
                .then(({ data }) => {
                    if (data) callback(data as T[])
                })

            // Then subscribe to changes
            const channel: RealtimeChannel = supabase
                .channel(`${tableName}_changes`)
                .on(
                    'postgres_changes',
                    { event: '*', schema: 'public', table: tableName },
                    async () => {
                        // Re-fetch all data on any change (simple and reliable)
                        const { data } = await supabase
                            .from(tableName)
                            .select('*')
                            .order('created_at', { ascending: false })
                        if (data) callback(data as T[])
                    }
                )
                .subscribe()

            return () => {
                supabase.removeChannel(channel)
            }
        },
        [tableName]
    )

    return {
        loading,
        error,
        insert,
        getAll,
        getById,
        update,
        remove,
        query,
        subscribe,
    }
}
